        )
        if products_info_str is None or products_info_str == "":
            close_page()
            continue

        products = []
        for entry in products_info_str.split(";"):
            entry = entry.strip()
            if not entry:
                continue
            parts = entry.split(",")
            capacity = None
            url = None
            for p in parts:
                p = p.strip()
                if p.startswith("capacity="):
                    capacity = p.replace("capacity=", "").strip()
                elif p.startswith("url="):
